// Bundle script — reads all .rego policy files and emits dist/index.mjs
import {
  readFileSync,
  readdirSync,
  statSync,
  mkdirSync,
  writeFileSync,
} from 'fs';
import { join, basename, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, '..');
const OUTPUT = join(ROOT, 'dist', 'index.mjs');

/** @param {string} str */
function toCamelCase(str) {
  return str.replace(/[-_]([a-zA-Z0-9])/g, (_, c) => c.toUpperCase());
}

/** @param {string} str */
function capitalize(str) {
  return str.charAt(0).toUpperCase() + str.slice(1);
}

function parseMetadata(source) {
  const metaMatch = source.match(/^# METADATA\n((?:#[^\n]*\n)*)/m);
  if (!metaMatch) return { title: '', description: '' };
  const block = metaMatch[1];
  const title = (block.match(/^# title:\s*(.+)$/m) || [])[1]?.trim() ?? '';
  const description =
    (block.match(/^# description:\s*(.+)$/m) || [])[1]?.trim() ?? '';
  return { title, description };
}

function findRegoFiles(dir) {
  const results = [];
  for (const entry of readdirSync(dir)) {
    const fullPath = join(dir, entry);
    if (statSync(fullPath).isDirectory()) {
      results.push(...findRegoFiles(fullPath));
    } else if (entry.endsWith('.rego') && !entry.endsWith('_test.rego')) {
      results.push(fullPath);
    }
  }
  return results;
}

// Auto-discover top-level directories that contain at least one non-test .rego file
function discoverCategories(root) {
  return readdirSync(root)
    .filter((entry) => {
      if (entry.startsWith('.')) return false;
      const fullPath = join(root, entry);
      return (
        statSync(fullPath).isDirectory() && findRegoFiles(fullPath).length > 0
      );
    })
    .sort();
}

function deriveKey(filePath, categoryDir) {
  const stem = basename(filePath, '.rego');
  // Files named 'policy' are disambiguated by their parent directory name
  const name = stem === 'policy' ? basename(dirname(filePath)) : stem;
  return toCamelCase(name);
}

const discoveredCategories = discoverCategories(ROOT);

// First pass: collect raw entries
const rawEntries = [];
for (const category of discoveredCategories) {
  const categoryDir = join(ROOT, category);
  for (const filePath of findRegoFiles(categoryDir).sort()) {
    const source = readFileSync(filePath, 'utf8');
    const { title, description } = parseMetadata(source);
    const baseKey = deriveKey(filePath, categoryDir);
    rawEntries.push({
      category,
      baseKey,
      policy: { title, description, source },
    });
  }
}

// Detect base keys that appear in more than one category
/** @type {Record<string, number>} */
const keyCounts = {};
for (const { baseKey } of rawEntries) {
  keyCounts[baseKey] = (keyCounts[baseKey] || 0) + 1;
}

// Assign final export keys, prefixing with camelCase category name for duplicates
const finalEntries = rawEntries.map(({ category, baseKey, policy }) => {
  const exportKey =
    keyCounts[baseKey] > 1
      ? toCamelCase(category) + capitalize(baseKey)
      : baseKey;
  return { category, exportKey, policy: { id: exportKey, ...policy } };
});

// Build category groups and flat map
/** @type {Record<string, Record<string, object>>} */
const categoryGroups = {};
/** @type {Record<string, object>} */
const allPolicies = {};
for (const { category, exportKey, policy } of finalEntries) {
  if (!categoryGroups[category]) categoryGroups[category] = {};
  categoryGroups[category][exportKey] = policy;
  allPolicies[exportKey] = policy;
}

// Generate the .mjs source
const lines = [
  '// Auto-generated by scripts/build-bundle.mjs — do not edit',
  '',
];

// Individual policy exports
for (const [key, policy] of Object.entries(allPolicies)) {
  lines.push(`export const ${key} = ${JSON.stringify(policy, null, 2)};`, '');
}

// Category collection exports (using camelCase JS identifier for the category name)
for (const category of discoveredCategories) {
  const catKey = toCamelCase(category);
  const keys = Object.keys(categoryGroups[category]).join(', ');
  lines.push(`export const ${catKey} = { ${keys} };`, '');
}

// Master collection + default export
const allCatKeys = discoveredCategories.map(toCamelCase).join(', ');
lines.push(`export const all = { ${allCatKeys} };`, '');
lines.push('export default all;', '');

mkdirSync(dirname(OUTPUT), { recursive: true });
writeFileSync(OUTPUT, lines.join('\n'), 'utf8');
console.log(
  `Built ${OUTPUT} (${Object.keys(allPolicies).length} policies across ${discoveredCategories.length} categories: ${discoveredCategories.join(', ')})`,
);
